// // This module implements a 9-bit shift register with serial load, a shift right, and a shift left enable signal. The register loads a given value (input [8:0] load_value) when load is high. The register has active high reset. The register's value should be output as a 9-bit bus (output [8:0] q).
module top_module(
	input clk,
	input load,
	input shift_left,
	input shift_right,
	input rst_n,
	input [7:0] load_value,
	output reg [7:0] q);
always @(posedge clk or negedge rst_n) begin
	if (!rst_n)
		q <= 8'b0;
	else if (load)
		q <= load_value;
	else if (shift_left)
		q <= q << 1;
	else if (shift_right)
		q <= q >> 1;
end

endmodule
